import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { getAuthUser, verifyProjectOwnership, handleAuthError } from '@/lib/auth-helpers'
import { CardType, CardStatus, Priority, ProjectPhase } from '@prisma/client'

/**
 * POST /api/projects/[id]/cards
 * Create a new card for a project
 */
export async function POST(
    req: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const user = await getAuthUser()
        const { id: projectId } = await params

        // Verify project ownership
        const project = await verifyProjectOwnership(projectId, user.id)

        // Get or create workspace for this project
        let workspace = await prisma.workspaces.findUnique({
            where: { project_id: projectId },
        })

        if (!workspace) {
            // Create workspace if it doesn't exist
            workspace = await prisma.workspaces.create({
                data: {
                    id: `ws_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`,
                    project_id: projectId,
                    view_settings: {},
                    updated_at: new Date(),
                },
            })
        }

        // Parse request body
        const body = await req.json()
        const { type, label, content, status, priority, position, phase, metadata, tags } = body

        // Validate required fields
        if (!type || !label) {
            return new Response('Missing required fields: type, label', { status: 400 })
        }

        // Validate type is a valid CardType
        if (!Object.values(CardType).includes(type)) {
            return new Response(`Invalid card type. Must be one of: ${Object.values(CardType).join(', ')}`, { status: 400 })
        }

        // Create card
        const card = await prisma.cards.create({
            data: {
                id: `card_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`,
                workspace_id: workspace.id,
                type: type as CardType,
                label,
                description: content || null,
                status: status || CardStatus.DRAFT,
                priority: priority || Priority.MEDIUM,
                position: position || { x: 0, y: 0 },
                phase: phase || null,
                metadata: metadata || {},
                tags: tags || [],
                updated_at: new Date(),
            },
        })

        return NextResponse.json({ success: true, data: card }, { status: 201 })
    } catch (error) {
        console.error('Create card error:', error)
        return handleAuthError(error)
    }
}

/**
 * GET /api/projects/[id]/cards
 * List cards for a project with optional filters
 * Query params: type, phase, status
 */
export async function GET(
    req: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const user = await getAuthUser()
        const { id: projectId } = await params

        // Verify project ownership
        await verifyProjectOwnership(projectId, user.id)

        // Get workspace for this project
        const workspace = await prisma.workspaces.findUnique({
            where: { project_id: projectId },
        })

        if (!workspace) {
            // No workspace means no cards
            return NextResponse.json({ success: true, data: [] })
        }

        // Parse query params for filters
        const searchParams = req.nextUrl.searchParams
        const typeFilter = searchParams.get('type')
        const phaseFilter = searchParams.get('phase')
        const statusFilter = searchParams.get('status')

        // Build filter object
        const where: any = {
            workspace_id: workspace.id,
        }

        if (typeFilter) {
            where.type = typeFilter as CardType
        }

        if (phaseFilter) {
            where.phase = phaseFilter as ProjectPhase
        }

        if (statusFilter) {
            where.status = statusFilter as CardStatus
        }

        // Fetch cards with filters
        const cards = await prisma.cards.findMany({
            where,
            orderBy: [
                { created_at: 'desc' }
            ],
        })

        return NextResponse.json({ success: true, data: cards })
    } catch (error) {
        console.error('List cards error:', error)
        return handleAuthError(error)
    }
}

