import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { getAuthUser, verifyCardOwnership, handleAuthError } from '@/lib/auth-helpers'
import { CardType, CardStatus, Priority, ProjectPhase } from '@prisma/client'

/**
 * PATCH /api/cards/[cardId]
 * Update an existing card
 */
export async function PATCH(
    req: NextRequest,
    { params }: { params: Promise<{ cardId: string }> }
) {
    try {
        const user = await getAuthUser()
        const { cardId } = await params

        // Verify card ownership
        await verifyCardOwnership(cardId, user.id)

        // Parse request body
        const body = await req.json()
        const { type, label, content, status, priority, position, phase, metadata, tags, validated } = body

        // Build update data object with only provided fields
        const updateData: any = {
            updated_at: new Date(),
        }

        if (type !== undefined) {
            // Validate type is a valid CardType
            if (!Object.values(CardType).includes(type)) {
                return new Response(`Invalid card type. Must be one of: ${Object.values(CardType).join(', ')}`, { status: 400 })
            }
            updateData.type = type as CardType
        }

        if (label !== undefined) {
            updateData.label = label
        }

        if (content !== undefined) {
            updateData.description = content
        }

        if (status !== undefined) {
            // Validate status is a valid CardStatus
            if (!Object.values(CardStatus).includes(status)) {
                return new Response(`Invalid card status. Must be one of: ${Object.values(CardStatus).join(', ')}`, { status: 400 })
            }
            updateData.status = status as CardStatus
        }

        if (priority !== undefined) {
            // Validate priority is a valid Priority
            if (!Object.values(Priority).includes(priority)) {
                return new Response(`Invalid priority. Must be one of: ${Object.values(Priority).join(', ')}`, { status: 400 })
            }
            updateData.priority = priority as Priority
        }

        if (position !== undefined) {
            updateData.position = position
        }

        if (phase !== undefined) {
            // Validate phase is a valid ProjectPhase or null
            if (phase !== null && !Object.values(ProjectPhase).includes(phase)) {
                return new Response(`Invalid phase. Must be one of: ${Object.values(ProjectPhase).join(', ')} or null`, { status: 400 })
            }
            updateData.phase = phase as ProjectPhase | null
        }

        if (metadata !== undefined) {
            updateData.metadata = metadata
        }

        if (tags !== undefined) {
            updateData.tags = tags
        }

        if (validated !== undefined) {
            updateData.validated = validated
            if (validated) {
                updateData.validated_at = new Date()
            }
        }

        // Update card
        const card = await prisma.cards.update({
            where: { id: cardId },
